import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApprovalDto, SponsorshipRequest } from 'src/app/core/models/request.model';
import { AuthService } from 'src/app/core/services/auth.service';
import { RequestService } from 'src/app/core/services/request.service';

@Component({
  selector: 'app-finance-details',
  templateUrl: './finance-details.component.html',
  styleUrls: ['./finance-details.component.css']
})
export class FinanceDetailsComponent {
  financeForm: FormGroup;
  requestId: number = 0;
  userId: number = 0;
  request: SponsorshipRequest | null = null;
  isLoading = false;
  isApproving = false;

  constructor(private fb: FormBuilder, private route: ActivatedRoute, private router: Router,
    private requestService: RequestService, private auth: AuthService) {
    this.financeForm = fb.group({
      remarks: ['', [Validators.required, Validators.minLength(10), Validators.maxLength(500)]]
    });
  }

  ngOnInit(): void {
    this.requestId = Number(this.route.snapshot.paramMap.get('id'));
    this.userId = this.auth.getCurrentUserId();
    this.loadRequestDetails();
  }

  get f() { return this.financeForm.controls; }

  loadRequestDetails() {
    this.isLoading = true;
    this.requestService.getRequestById(this.requestId).subscribe({
      next: (request) => {
        request.status = this.mapStatusToString(Number(request.status));
        this.request = new SponsorshipRequest(request);
        this.isLoading = false;
      },
      error: (error) => {
        console.error('Error:', error);
        this.isLoading = false;
        alert('Error loading request details');
      }
    });
  }

  mapStatusToString(status: number): string {
    const statusMap: { [key: number]: string } = {
      1: 'Draft',
      2: 'PendingManager',
      3: 'PendingFinance',
      4: 'Approved',
      5: 'Rejected',
      6: 'Cancelled'
    };
    return statusMap[status] || 'Draft';
  }

  canSubmit(): boolean {
    return this.request?.status === 'PendingManager';
  }

  goBack() {
    this.router.navigate(['/manager/pending']);
  }

  onApproved() {
    if (!this.canSubmit()) {
      alert('Only pending manager requests can be approved');
      return;
    }

    const submitData = new ApprovalDto({
      requestId: this.requestId,
      userId: this.userId,
      remarks: this.financeForm.value.remarks
    });

    if (confirm('Are you sure you want to approve this request?')) {
      this.isApproving = true;
      this.requestService.approveByManager(submitData).subscribe({
        next: (res) => {
          this.isApproving = false;
          alert(res.message);
          this.router.navigate(['/requestor/my-requests']);
        },
        error: (error) => {
          this.isApproving = false;
          alert(error.error?.message || 'Error submitting request');
        }
      });
    }
  }

  rejectRequest(id: number) {
      const submitData = new ApprovalDto({
      requestId: this.requestId,
      userId: this.userId,
      remarks: this.financeForm.value.remarks
    });

    if (confirm('Are you sure you want to reject this request?')) {
      this.isApproving = true;
      this.requestService.rejectByManager(submitData).subscribe({
        next: (res) => {
          this.isApproving = false;
          alert(res.message);
          this.router.navigate(['/requestor/my-requests']);
        },
        error: (error) => {
          this.isApproving = false;
          alert(error.error?.message || 'Error submitting request');
        }
      });
    }
  }
}
<div class="container mt-4">
  <div class="card" *ngIf="!isLoading && request">
    <div class="card-header">
      <h3>Request Details</h3>
      <span class="badge" [class]="request.getStatusClass()">
        {{ request.getStatusText() }}
      </span>
    </div>

    <div class="card-body">
      <form [formGroup]="financeForm">
      <div class="row">
        <div class="col-md-6">
          <p><strong>Title:</strong> {{ request.title }}</p>
          <p><strong>Department:</strong> {{ request.department }}</p>
          <p><strong>Event Name:</strong> {{ request.eventName }}</p>
          <p><strong>Event Date:</strong> {{ request.eventDate | date }}</p>
        </div>
        <div class="col-md-6">
          <p><strong>Amount:</strong> ${{ request.requestedAmount }}</p>
          <p><strong>Status:</strong> {{ request.getStatusText() }}</p>
          <p><strong>Created:</strong> {{ request.createdAt | date }}</p>
        </div>
      </div>

      <div class="row mt-3">
        <div class="col-12">
          <p><strong>Justification:</strong></p>
          <p>{{ request.justification }}</p>
        </div>
      </div>

      <div class="form-section">
        <h3 class="section-title">
          <i class="fas fa-comment"></i>
          Add Remarks <span class="required">*</span>
        </h3>

        <div class="form-row">
          <div class="form-group full-width">
             <textarea id="remarks" formControlName="remarks" class="form-control" rows="4"
              [class.is-invalid]="f['remarks'].invalid" placeholder="Add remarks"></textarea>
            <div class="invalid-feedback" *ngIf="f['remarks'].invalid">
              <span *ngIf="f['remarks'].errors?.['required']">Remarks is required</span>
              <span *ngIf="f['remarks'].errors?.['minlength']">Remarks must be at least 10 characters</span>
            </div>
          </div>
        </div>
      </div>
      </form>
    </div>

    <div class="card-footer">
      <button class="btn btn-secondary" (click)="goBack()">Back</button>
      <button class="btn-edit" (click)="rejectRequest(request.id)" title="Edit" *ngIf="request.status === 'PendingManager'">Reject</button>
      <button class="btn btn-primary" (click)="onApproved()" [disabled]="!canSubmit() || isApproving">
        <i *ngIf="isApproving" class="fas fa-spinner fa-spin"></i>
        {{ isApproving ? 'Approving...' : 'Approve' }}
      </button>
    </div>
  </div>
</div>
